class Solution:
    def maximumPoints(self, enemyEnergies, currentEnergy: int) -> int:
        min_e = min(enemyEnergies)
        if currentEnergy < min_e:
            return 0
        total = currentEnergy + sum(enemyEnergies) - min_e
        return total // min_e

